class Solution {
    public int maxStability(int n, int[][] edges, int k) {
        int[] edgeStrengths = new int[n];
        int[] edgeMusts = new int[n];
        int maxStability = -1;

        for (int[] edge : edges) {
            edgeStrengths[edge[1]] = edge[2];
            edgeMusts[edge[1]] = edge[3];
        }

        for (int i = 0; i < n; i++) {
            int minStrength = Integer.MAX_VALUE;
            for (int j = 0; j < n; j++) {
                if (edgeMusts[i] == edgeMusts[j]) {
                    minStrength = Math.min(minStrength, edgeStrengths[j]);
            }
        }
        maxStability = Math.min(maxStability, minStrength);
    }

    return maxStability;
}
